import{_ as t,H as s,f as l,i}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"算法与数据结构系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"algorithmLearning/00-写作计划.md","filePath":"algorithmLearning/00-写作计划.md","lastUpdated":1778496697000}'),n={name:"algorithmLearning/00-写作计划.md"};function e(o,a,r,d,p,h){return s(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="算法与数据结构系列写作计划" tabindex="-1">算法与数据结构系列写作计划 <a class="header-anchor" href="#算法与数据结构系列写作计划" aria-label="Permalink to &quot;算法与数据结构系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> → B. algorithms ⭐⭐⭐⭐⭐。 这个系列<strong>不是 LeetCode 刷题册</strong>,是&quot;工程师真用得上的算法心智模型&quot;——让你写代码时直觉就知道复杂度、选数据结构时不用猜、读别人代码时一眼看出套路。</p><p><strong>和刷题网站的根本区别</strong>:刷题网站按题号走,讲&quot;这题怎么做&quot;;本系列按<strong>心智模型</strong>走,讲&quot;一类问题为什么长这样、套路是怎么抽象出来的&quot;。刷完 100 道题还懵,是因为没把套路抽成可迁移的结构。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>四层结构,从&quot;底层武器库&quot;到&quot;实战工程&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础心智 + 复杂度(01-03)</span></span>
<span class="line"><span>   → 线性结构(数组 / 链表 / 栈 / 队列 / 哈希)(04-08)</span></span>
<span class="line"><span>   → 树与图(树 / BST / 堆 / Trie / 并查集 / 图)(09-14)</span></span>
<span class="line"><span>   → 算法范式(排序 / 二分 / 双指针 / 滑窗 / DP / 回溯 / 贪心 / 分治)(15-22)</span></span>
<span class="line"><span>   → 工程实战(LRU / 限流 / 一致性哈希 / 布隆过滤器 / 调度)(23-28)</span></span></code></pre></div><p><strong>一个判断标准</strong>:看完某一篇后,你再遇到这类问题时,应该<strong>不是回头翻这篇</strong>,而是<strong>条件反射知道怎么拆</strong>。做不到就是讲得不够本质。</p><hr><h2 id="和其他系列的边界" tabindex="-1">和其他系列的边界 <a class="header-anchor" href="#和其他系列的边界" aria-label="Permalink to &quot;和其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>限流算法(令牌桶 / 漏桶)</td><td>backendLearning 讲过用法</td><td>讲<strong>实现原理 + 代码</strong></td></tr><tr><td>一致性哈希</td><td>systemDesign 未写 / Redis 提过</td><td>讲<strong>算法本身 + 虚拟节点</strong></td></tr><tr><td>LRU 缓存</td><td>Redis / 操作系统提过</td><td>讲<strong>数据结构实现</strong></td></tr><tr><td>字符串匹配(KMP / Rabin-Karp)</td><td>—</td><td>本系列独讲</td></tr><tr><td>图数据库底层</td><td>—</td><td>只讲图算法,不讲 Neo4j</td></tr><tr><td>并发数据结构</td><td>—</td><td>只讲单线程数据结构,并发留给 os/并发系列</td></tr></tbody></table><p><strong>不做什么</strong>:</p><ul><li>不按 LeetCode 编号讲题;<strong>按套路分类讲</strong></li><li>不堆证明;复杂度推导只讲直觉 + 关键步骤</li><li>不讲 ACM 竞赛级技巧(后缀自动机 / 李超线段树之类);<strong>只覆盖工程工程师 80% 会用上的</strong></li></ul><hr><h2 id="篇目-28-篇" tabindex="-1">篇目(28 篇) <a class="header-anchor" href="#篇目-28-篇" aria-label="Permalink to &quot;篇目(28 篇)&quot;">​</a></h2><h3 id="第一层-心智与复杂度-01-03" tabindex="-1">第一层:心智与复杂度(01-03) <a class="header-anchor" href="#第一层-心智与复杂度-01-03" aria-label="Permalink to &quot;第一层:心智与复杂度(01-03)&quot;">​</a></h3><ul><li>[x] 01 算法总览与工程师心智(为什么要学、学到什么程度)</li><li>[x] 02 时间与空间复杂度(大 O / 均摊 / 最坏 vs 期望)</li><li>[x] 03 递归与递推(自顶向下 vs 自底向上 / 主定理直觉)</li></ul><h3 id="第二层-线性数据结构-04-08" tabindex="-1">第二层:线性数据结构(04-08) <a class="header-anchor" href="#第二层-线性数据结构-04-08" aria-label="Permalink to &quot;第二层:线性数据结构(04-08)&quot;">​</a></h3><ul><li>[x] 04 数组与动态数组(ArrayList / 扩容均摊 / 缓存友好性)</li><li>[x] 05 链表(单链 / 双链 / 环 / 快慢指针套路)</li><li>[x] 06 栈与队列(单调栈 / 单调队列 / 双端队列)</li><li>[x] 07 哈希表(冲突 / 开放寻址 vs 拉链 / 负载因子 / 扰动函数)</li><li>[x] 08 字符串(KMP / Rabin-Karp / Trie 预告)</li></ul><h3 id="第三层-树与图-09-14" tabindex="-1">第三层:树与图(09-14) <a class="header-anchor" href="#第三层-树与图-09-14" aria-label="Permalink to &quot;第三层:树与图(09-14)&quot;">​</a></h3><ul><li>[x] 09 树与二叉树(遍历四法 / 递归与迭代 / Morris)</li><li>[x] 10 BST / AVL / 红黑树(平衡的代价与收益)</li><li>[x] 11 堆与优先队列(Top K / 中位数 / 堆排序)</li><li>[x] 12 Trie 字典树(前缀 / 自动补全 / 敏感词过滤)</li><li>[x] 13 并查集(路径压缩 + 按秩合并 / 实战连通性)</li><li>[x] 14 图论基础(存储 / BFS / DFS / 拓扑排序 / 最短路径)</li></ul><h3 id="第四层-算法范式-15-22" tabindex="-1">第四层:算法范式(15-22) <a class="header-anchor" href="#第四层-算法范式-15-22" aria-label="Permalink to &quot;第四层:算法范式(15-22)&quot;">​</a></h3><ul><li>[x] 15 排序全家桶(快排 / 归并 / 堆排 / 计数 / 基数 / 稳定性)</li><li>[x] 16 二分查找(边界 / 二分答案 / 在旋转数组里二分)</li><li>[x] 17 双指针与滑动窗口(定长 / 变长 / 最小覆盖子串套路)</li><li>[x] 18 动态规划入门(状态定义 / 转移 / 无后效性)</li><li>[x] 19 动态规划进阶(背包 / 区间 / 状压 / 树形 DP)</li><li>[x] 20 回溯(DFS + 剪枝 / 全排列 / 组合 / N 皇后)</li><li>[x] 21 贪心(交换论证 / 区间调度 / 哈夫曼)</li><li>[x] 22 分治(归并 / 快排 / 逆序对 / 最近点对)</li></ul><h3 id="第五层-工程实战-23-28" tabindex="-1">第五层:工程实战(23-28) <a class="header-anchor" href="#第五层-工程实战-23-28" aria-label="Permalink to &quot;第五层:工程实战(23-28)&quot;">​</a></h3><ul><li>[x] 23 LRU / LFU 缓存(哈希 + 双向链表)</li><li>[x] 24 限流算法(固定窗口 / 滑动窗口 / 漏桶 / 令牌桶)</li><li>[x] 25 一致性哈希(虚拟节点 / 雪崩避免)</li><li>[x] 26 布隆过滤器与 Count-Min Sketch(概率数据结构)</li><li>[x] 27 调度算法(时间轮 / 优先队列调度 / 工作窃取)</li><li>[x] 28 算法选型手册与面试实战(题型模板 / 心智地图)</li></ul><hr><h2 id="完结-2026-05-08" tabindex="-1">完结(2026/05/08) <a class="header-anchor" href="#完结-2026-05-08" aria-label="Permalink to &quot;完结(2026/05/08)&quot;">​</a></h2><p>28 篇全部完成,跟原计划完全一致。下一步:</p><ul><li>配合做一个带算法的小项目(限流中间件 / LRU 缓存 / 短链系统),把第五层的&quot;实战&quot;五篇做成真东西</li><li>按&quot;按套路分组刷题&quot;的方法,做 5-10 道每个范式的代表题,把模板练成肌肉记忆</li><li>不熟的题型回头翻对应那篇,出事故 / 性能问题时第一反应是&quot;这是哪个套路&quot;,而不是从头硬想</li></ul><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-03  心智必看,跳过去后面会&quot;不知道自己不知道&quot;</span></span>
<span class="line"><span>04-08  线性结构,日常 70% 代码用的就这些</span></span>
<span class="line"><span>09-14  树和图,复杂业务 / 系统设计的基础</span></span>
<span class="line"><span>15-22  算法范式,面试硬通货</span></span>
<span class="line"><span>23-28  工程实战,跟 backend / systemDesign 咬合</span></span></code></pre></div><p><strong>硬指标</strong>:看完 22 篇后,面对一道陌生题,你应该能在 1 分钟内<strong>分类</strong>(这是 DP? 滑窗? BFS?)。分类对了,套路就来了;分类错了,刷再多题也是白刷。</p><hr><h2 id="代码语言" tabindex="-1">代码语言 <a class="header-anchor" href="#代码语言" aria-label="Permalink to &quot;代码语言&quot;">​</a></h2><p>统一用 <strong>TypeScript / Python 伪代码</strong>:</p><ul><li>TS 读起来像 Java / JS / C 的平均,业内接受度最高</li><li>Python 语法最贴近教科书伪代码</li><li>关键算法给两个版本</li></ul><hr><h2 id="预计时间线" tabindex="-1">预计时间线 <a class="header-anchor" href="#预计时间线" aria-label="Permalink to &quot;预计时间线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 线性(01-08) → 约 1-2 周</span></span>
<span class="line"><span>树与图(09-14)     → 约 1 周</span></span>
<span class="line"><span>算法范式(15-22)   → 约 2 周(DP 两篇最慢)</span></span>
<span class="line"><span>工程实战(23-28)   → 约 1 周(写得快,因为套路已经铺过)</span></span></code></pre></div><p>跟规划里的节奏建议一致:<strong>不建议连开新系列</strong>,写这个系列时可以配合做 1-2 个带算法的项目(比如自己实现 LRU、写个限流中间件)。</p>`,40)])])}const g=t(n,[["render",e]]);export{u as __pageData,g as default};
